-- Modify "shipments" table
ALTER TABLE "shipments" ADD CONSTRAINT "shipments_finance_release_status_allowed" CHECK ((finance_release_status)::text = ANY ((ARRAY['PENDING'::character varying, 'APPROVED'::character varying, 'REJECTED'::character varying])::text[])), ADD CONSTRAINT "shipments_finance_release_version_positive" CHECK (finance_release_version > 0), ADD COLUMN "finance_release_status" character varying NOT NULL DEFAULT 'PENDING', ADD COLUMN "finance_release_version" bigint NOT NULL DEFAULT 1, ADD COLUMN "finance_released_at" timestamptz NULL, ADD COLUMN "finance_released_by" bigint NULL, ADD COLUMN "finance_release_process_instance_id" bigint NULL, ADD COLUMN "finance_release_process_node_id" bigint NULL, ADD COLUMN "finance_release_note" character varying NULL;
